package com.restaurantcraft.registry;
import com.restaurantcraft.RestaurantCraft; import com.restaurantcraft.menu.*; import net.minecraft.world.inventory.MenuType; import net.minecraft.world.level.block.entity.BlockEntity; import net.minecraftforge.common.extensions.IForgeMenuType; import net.minecraftforge.eventbus.api.IEventBus; import net.minecraftforge.registries.*;
public class ModMenuTypes { public static final DeferredRegister<MenuType<?>> MENUS=DeferredRegister.create(ForgeRegistries.MENU_TYPES,RestaurantCraft.MODID); public static final RegistryObject<MenuType<RestaurantManagementMenu>> RESTAURANT_MANAGEMENT=MENUS.register("restaurant_management",()->IForgeMenuType.create((id,inv,buf)->new RestaurantManagementMenu(id,inv,(com.restaurantcraft.blockentity.RestaurantManagementBlockEntity)inv.player.level().getBlockEntity(buf.readBlockPos())))); public static final RegistryObject<MenuType<CookingDeviceMenu>> COOKING_DEVICE=MENUS.register("cooking_device",()->IForgeMenuType.create((id,inv,buf)->{BlockEntity be=inv.player.level().getBlockEntity(buf.readBlockPos()); return new CookingDeviceMenu(id,inv,be);})); public static final RegistryObject<MenuType<CustomerOrderMenu>> CUSTOMER_ORDER=MENUS.register("customer_order",()->IForgeMenuType.create((id,inv,buf)->new CustomerOrderMenu(id,inv,buf.readInt()))); public static void register(IEventBus bus){MENUS.register(bus);} }
